import{_ as t,o as i,c as l,a2 as e}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"Share 分享","description":"","frontmatter":{"title":"Share 分享","stage":"intermediate","direction":"interaction-design","tags":["interaction-patterns","collaboration","sharing"]},"headers":[],"relativePath":"03-interaction-design/notes/06-interaction-patterns/05-collaboration/share.md","filePath":"03-interaction-design/notes/06-interaction-patterns/05-collaboration/share.md","lastUpdated":1784542968000}'),r={name:"03-interaction-design/notes/06-interaction-patterns/05-collaboration/share.md"};function d(n,a,o,h,s,c){return i(),l("div",null,[...a[0]||(a[0]=[e(`<h1 id="share-分享" tabindex="-1">Share 分享 <a class="header-anchor" href="#share-分享" aria-label="Permalink to &quot;Share 分享&quot;">​</a></h1><p>Share 是为资源创建、修改或撤销访问关系的授权操作。分享界面必须准确表达“哪个主体、对哪个资源、可以做什么、在什么条件下、持续多久”，并让所有有效权限和链接可被复核。</p><h2 id="能力边界与前置知识" tabindex="-1">能力边界与前置知识 <a class="header-anchor" href="#能力边界与前置知识" aria-label="Permalink to &quot;能力边界与前置知识&quot;">​</a></h2><p>本文聚焦：</p><ul><li>直接 ACL、群组、继承权限和链接分享的差异。</li><li>查看、评论、编辑、管理等角色的能力边界。</li><li>外部协作者身份验证、邀请与到期。</li><li>链接复制、传播风险、撤销与轮换。</li><li>有效权限计算、审计、缓存失效和并发修改。</li></ul><p>前置知识：</p><ul><li>能定义资源、主体、动作和组织边界。</li><li>理解前端隐藏不能替代服务端授权。</li><li>能区分分享授权、通知投递和内容引用。</li></ul><p>分享不是“把 URL 复制出去”。规范 URL 只标识资源；是否授予访问由 ACL、策略或具备访问能力的秘密链接决定。</p><h2 id="授权的五个要素" tabindex="-1">授权的五个要素 <a class="header-anchor" href="#授权的五个要素" aria-label="Permalink to &quot;授权的五个要素&quot;">​</a></h2><p>[ Decision = f(Principal, Resource, Action, Context, Policy) ]</p><ul><li><code>Principal</code>：用户、群组、组织、服务账号或匿名链接持有者。</li><li><code>Resource</code>：文档、文件夹、报表、项目或其特定版本。</li><li><code>Action</code>：read、comment、edit、share、download、delete 等。</li><li><code>Context</code>：时间、组织、设备、网络、数据分类和会话风险。</li><li><code>Policy</code>：ACL、继承、组织规则、外部协作限制和保留策略。</li></ul><p>界面的“查看者”“编辑者”是能力集合的产品名称，不是跨产品通用标准。每个角色要展开实际动作。</p><h2 id="acl-数据模型" tabindex="-1">ACL 数据模型 <a class="header-anchor" href="#acl-数据模型" aria-label="Permalink to &quot;ACL 数据模型&quot;">​</a></h2><h3 id="access-control-entry" tabindex="-1">Access Control Entry <a class="header-anchor" href="#access-control-entry" aria-label="Permalink to &quot;Access Control Entry&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>作用</th></tr></thead><tbody><tr><td><code>grant_id</code></td><td>一次授权的稳定标识</td></tr><tr><td><code>resource_id</code></td><td>被授权资源</td></tr><tr><td><code>principal_type</code></td><td>user、group、domain、organization、link</td></tr><tr><td><code>principal_id</code></td><td>主体或链接能力稳定 ID</td></tr><tr><td><code>role_id</code></td><td>角色定义</td></tr><tr><td><code>source</code></td><td>direct、inherited、policy、link</td></tr><tr><td><code>granted_by</code></td><td>授权主体</td></tr><tr><td><code>granted_at</code></td><td>服务端授权时间</td></tr><tr><td><code>expires_at</code></td><td>可选到期时间</td></tr><tr><td><code>conditions</code></td><td>允许的上下文条件</td></tr><tr><td><code>status</code></td><td>pending、active、expired、revoked</td></tr><tr><td><code>version</code></td><td>并发修改版本</td></tr></tbody></table><p>ACL 只存允许关系还是同时存拒绝关系，取决于授权模型。若支持 deny，需要明确它与 direct allow、group allow、继承 allow 的优先级；不能让界面自行猜测。</p><h3 id="有效权限" tabindex="-1">有效权限 <a class="header-anchor" href="#有效权限" aria-label="Permalink to &quot;有效权限&quot;">​</a></h3><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    U[&quot;当前主体&quot;] --&gt; D[&quot;直接授权&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    U --&gt; G[&quot;群组与组织成员关系&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    R[&quot;当前资源&quot;] --&gt; I[&quot;父级继承授权&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    R --&gt; L[&quot;有效链接授权&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; P[&quot;策略合并&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; P</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    I --&gt; P</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    L --&gt; P</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C[&quot;时间、外部协作、数据分类&quot;] --&gt; P</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    P --&gt; E[&quot;有效动作集合&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; A{&quot;本次动作允许？&quot;}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>“在共享列表中没有此人”不代表无权限，他可能通过群组、父文件夹或组织链接获得访问。分享界面应展示有效来源，至少能解释为何有权访问。</p><h2 id="角色与动作" tabindex="-1">角色与动作 <a class="header-anchor" href="#角色与动作" aria-label="Permalink to &quot;角色与动作&quot;">​</a></h2><p>一个示例角色表：</p><table tabindex="0"><thead><tr><th>动作</th><th style="text-align:right;">查看者</th><th style="text-align:right;">评论者</th><th style="text-align:right;">编辑者</th><th style="text-align:right;">管理者</th></tr></thead><tbody><tr><td>查看内容</td><td style="text-align:right;">是</td><td style="text-align:right;">是</td><td style="text-align:right;">是</td><td style="text-align:right;">是</td></tr><tr><td>下载</td><td style="text-align:right;">按资源策略</td><td style="text-align:right;">按资源策略</td><td style="text-align:right;">按资源策略</td><td style="text-align:right;">按资源策略</td></tr><tr><td>评论</td><td style="text-align:right;">否</td><td style="text-align:right;">是</td><td style="text-align:right;">是</td><td style="text-align:right;">是</td></tr><tr><td>修改正文</td><td style="text-align:right;">否</td><td style="text-align:right;">否</td><td style="text-align:right;">是</td><td style="text-align:right;">是</td></tr><tr><td>删除资源</td><td style="text-align:right;">否</td><td style="text-align:right;">否</td><td style="text-align:right;">依产品规则</td><td style="text-align:right;">是</td></tr><tr><td>邀请他人</td><td style="text-align:right;">否</td><td style="text-align:right;">否</td><td style="text-align:right;">依组织策略</td><td style="text-align:right;">是</td></tr><tr><td>修改 ACL</td><td style="text-align:right;">否</td><td style="text-align:right;">否</td><td style="text-align:right;">否</td><td style="text-align:right;">是</td></tr><tr><td>转移所有权</td><td style="text-align:right;">否</td><td style="text-align:right;">否</td><td style="text-align:right;">否</td><td style="text-align:right;">按组织策略</td></tr></tbody></table><p>“阻止下载”不能阻止有查看能力的人通过截图、拍照或手工复制所有信息。它只限制产品提供的下载功能，不应被承诺为绝对防泄漏。</p><p>角色变更是授权写入，需要重新检查操作者是否仍有管理权限，并防止最后一个必要管理者被误移除。</p><h2 id="直接分享" tabindex="-1">直接分享 <a class="header-anchor" href="#直接分享" aria-label="Permalink to &quot;直接分享&quot;">​</a></h2><h3 id="选择主体" tabindex="-1">选择主体 <a class="header-anchor" href="#选择主体" aria-label="Permalink to &quot;选择主体&quot;">​</a></h3><p>候选目录先按当前操作者可发现范围过滤，再标明：</p><ul><li>已有访问者。</li><li>同组织可邀请者。</li><li>允许邀请的外部身份。</li><li>因策略不可邀请的主体。</li></ul><p>同名用户使用最小必要信息消歧，不显示完整私人联系方式。</p><h3 id="邀请" tabindex="-1">邀请 <a class="header-anchor" href="#邀请" aria-label="Permalink to &quot;邀请&quot;">​</a></h3><p>邀请与授权可以分为：</p><ol><li>创建 pending invitation。</li><li>发送通知。</li><li>收件人完成身份验证。</li><li>校验邀请目标身份、域和到期时间。</li><li>激活 grant。</li></ol><p>若业务要求“发出邀请即获得权限”，也必须说明未登录访问怎样绑定到正确身份。仅凭邮件地址文本不能证明实际登录者拥有该地址。</p><h3 id="通知" tabindex="-1">通知 <a class="header-anchor" href="#通知" aria-label="Permalink to &quot;通知&quot;">​</a></h3><p>通知投递失败不一定回滚已创建授权。界面必须准确说明：</p><ul><li>“已授予访问，但邮件未发送。”</li><li>“邀请尚待接受。”</li><li>“邀请创建失败，未授予访问。”</li></ul><p>授权数据库和邮件队列是两个结果，不要合成一个模糊成功状态。</p><h2 id="群组、组织与域分享" tabindex="-1">群组、组织与域分享 <a class="header-anchor" href="#群组、组织与域分享" aria-label="Permalink to &quot;群组、组织与域分享&quot;">​</a></h2><p>群组授权便于成员变动，但使有效权限来自动态成员关系：</p><ul><li>新成员加入群组后获得资源访问。</li><li>成员移除后应及时失效。</li><li>嵌套群组可能增加解释和缓存失效成本。</li><li>外部成员是否可加入群组由组织政策决定。</li><li>历史审计需要回答某一时刻群组中有哪些实际成员。</li></ul><p>“组织内任何人”通常要求登录到指定租户；“某邮箱域”未必等同于同一组织身份。域所有权、受管账号和联合身份策略要由身份系统决定。</p><p>Google Drive API 的 permission scope 可为 user、group、domain 或 anyone，role 决定能力。Microsoft Graph 的链接 scope 可为 anonymous、organization 或 users。它们是各自平台的具体模型，产品应定义自己的语义而不是照抄名称。</p><h2 id="继承权限" tabindex="-1">继承权限 <a class="header-anchor" href="#继承权限" aria-label="Permalink to &quot;继承权限&quot;">​</a></h2><h3 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h3><p>文件夹、项目或空间可以向子资源传递授权。子资源页面需要显示：</p><ul><li>直接授权。</li><li>继承自哪个父级。</li><li>组织策略授予。</li><li>链接授予。</li></ul><p>对继承项的“移除”可能不可用，或实际操作是从父级移除、移动资源、停止继承、添加 deny。界面必须说明影响范围。</p><h3 id="移动资源" tabindex="-1">移动资源 <a class="header-anchor" href="#移动资源" aria-label="Permalink to &quot;移动资源&quot;">​</a></h3><p>资源从文件夹 A 移到 B 时，有效权限可能改变。移动前要计算：</p><ul><li>哪些主体会获得访问。</li><li>哪些主体会失去访问。</li><li>哪些直接 ACL 保留。</li><li>现有外部链接是否继续有效。</li><li>评论、搜索、通知和缓存如何更新。</li></ul><p>移动成功后异步索引未刷新，不能让旧权限继续从搜索或预览泄露。</p><h3 id="停止继承" tabindex="-1">停止继承 <a class="header-anchor" href="#停止继承" aria-label="Permalink to &quot;停止继承&quot;">​</a></h3><p>常见方式：</p><table tabindex="0"><thead><tr><th>方式</th><th>结果</th><th>风险</th></tr></thead><tbody><tr><td>复制当前有效 ACL 为直接项</td><td>当下访问不变，未来与父级脱钩</td><td>ACL 数量膨胀</td></tr><tr><td>只保留原直接项</td><td>立即移除继承访问</td><td>可能让协作者失联</td></tr><tr><td>添加受控例外</td><td>保留继承并限制某动作</td><td>优先级难解释</td></tr><tr><td>禁止停止继承</td><td>结构简单</td><td>无法隔离敏感子项</td></tr></tbody></table><p>选择必须由数据分类和组织政策约束。</p><h2 id="链接分享" tabindex="-1">链接分享 <a class="header-anchor" href="#链接分享" aria-label="Permalink to &quot;链接分享&quot;">​</a></h2><h3 id="链接类型" tabindex="-1">链接类型 <a class="header-anchor" href="#链接类型" aria-label="Permalink to &quot;链接类型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>访问主体</th><th>身份可追踪性</th><th>适用风险</th></tr></thead><tbody><tr><td>指定用户链接</td><td>被列出的登录用户</td><td>高</td><td>外部审阅</td></tr><tr><td>组织链接</td><td>指定组织的登录用户</td><td>中到高</td><td>内部广泛分发</td></tr><tr><td>匿名能力链接</td><td>持有链接的任何人</td><td>低</td><td>低敏感、短期内容</td></tr><tr><td>一次性链接</td><td>首次合法使用者</td><td>取决于绑定方式</td><td>单次领取或验证</td></tr><tr><td>公开链接</td><td>所有人且可被索引</td><td>低</td><td>明确公开内容</td></tr></tbody></table><p>匿名链接本质上是 capability URL：持有 URL 的主体获得相应能力。W3C TAG 指出这类 URL 可能暴露在浏览历史、日志、Referrer、第三方脚本和同步服务中，因此不应默认用于高风险资源。</p><h3 id="token-设计" tabindex="-1">Token 设计 <a class="header-anchor" href="#token-设计" aria-label="Permalink to &quot;Token 设计&quot;">​</a></h3><ul><li>使用不可猜的高熵随机值，不用连续编号。</li><li>服务端只存 token 的安全摘要，泄露数据库时降低直接使用风险。</li><li>每条链接拥有独立 <code>grant_id</code>，可单独撤销。</li><li>token 不进入分析事件、错误日志和第三方脚本。</li><li>URL 使用 HTTPS。</li><li>页面控制 Referrer，并避免不可信第三方资源。</li><li>GET 只读取，不通过访问链接执行删除等副作用。</li><li>规范资源 URL 与能力链接分开。</li></ul><p><code>robots.txt</code> 不能保护秘密链接；它是爬虫约定，而且列出具体路径本身可能泄露结构。</p><h3 id="链接配置" tabindex="-1">链接配置 <a class="header-anchor" href="#链接配置" aria-label="Permalink to &quot;链接配置&quot;">​</a></h3><p>创建前明确：</p><ul><li>角色：view、comment 或其他。</li><li>范围：指定用户、组织、匿名。</li><li>到期时间与时区。</li><li>是否需要密码或二次验证。</li><li>是否允许下载。</li><li>是否允许再次分享。</li><li>当前组织策略是否允许。</li></ul><p>密码与链接若通过同一渠道发送，附加保护有限。密码尝试需要限流，且密码本身安全存储。</p><h3 id="复制" tabindex="-1">复制 <a class="header-anchor" href="#复制" aria-label="Permalink to &quot;复制&quot;">​</a></h3><p>“复制链接”只在浏览器剪贴板写入成功后显示成功状态。失败时提供可选择的文本或重试，不能宣称已复制。</p><p>复制前或复制旁持续显示：</p><ul><li>谁可以打开。</li><li>能做什么。</li><li>何时到期。</li><li>怎样撤销。</li></ul><p>不要只用图标或颜色区分“任何人可访问”与“仅受邀者”。</p><h2 id="过期、撤销与轮换" tabindex="-1">过期、撤销与轮换 <a class="header-anchor" href="#过期、撤销与轮换" aria-label="Permalink to &quot;过期、撤销与轮换&quot;">​</a></h2><h3 id="过期" tabindex="-1">过期 <a class="header-anchor" href="#过期" aria-label="Permalink to &quot;过期&quot;">​</a></h3><p><code>expires_at</code> 使用明确时区并由服务端执行。到期任务失败也不能让链接继续有效；授权检查直接比较当前服务端时间。</p><p>到期后：</p><ul><li>链接访问返回过期或不可用结果。</li><li>缓存与 CDN 不再提供受限内容。</li><li>搜索、缩略图和嵌入失效。</li><li>当前打开的会话在下一次敏感请求重新授权。</li><li>UI 将 grant 标为 expired，而不是 active。</li></ul><h3 id="撤销" tabindex="-1">撤销 <a class="header-anchor" href="#撤销" aria-label="Permalink to &quot;撤销&quot;">​</a></h3><p>撤销是写操作：</p><ol><li>校验操作者权限与 grant 版本。</li><li>将 grant 状态改为 revoked。</li><li>使授权缓存失效。</li><li>停止未发送邀请和通知。</li><li>终止或缩短已有会话能力。</li><li>记录审计事件。</li></ol><p>已经下载的副本不能通过撤销召回，界面必须避免这种承诺。</p><h3 id="轮换" tabindex="-1">轮换 <a class="header-anchor" href="#轮换" aria-label="Permalink to &quot;轮换&quot;">​</a></h3><p>怀疑链接泄露时创建新链接并撤销旧链接。不要让多个不同 token 指向同一个不可区分的 grant，否则无法单独撤销或审计。</p><h3 id="删除资源" tabindex="-1">删除资源 <a class="header-anchor" href="#删除资源" aria-label="Permalink to &quot;删除资源&quot;">​</a></h3><p>资源删除应使所有 grant 和 capability URL 失效。恢复资源时，是否恢复旧分享必须按产品策略明确；高敏感资源通常需要重新确认，而不是自动复活旧匿名链接。</p><h2 id="分享面板的信息架构" tabindex="-1">分享面板的信息架构 <a class="header-anchor" href="#分享面板的信息架构" aria-label="Permalink to &quot;分享面板的信息架构&quot;">​</a></h2><h3 id="当前访问" tabindex="-1">当前访问 <a class="header-anchor" href="#当前访问" aria-label="Permalink to &quot;当前访问&quot;">​</a></h3><p>按来源展示：</p><ul><li>直接用户和群组。</li><li>继承访问。</li><li>组织或域范围。</li><li>活跃链接。</li><li>待接受邀请。</li><li>已到期或已撤销项（可放审计区域）。</li></ul><p>用户需要回答“谁现在能访问”，因此默认视图应显示有效权限，不只显示自己创建的邀请。</p><h3 id="添加访问" tabindex="-1">添加访问 <a class="header-anchor" href="#添加访问" aria-label="Permalink to &quot;添加访问&quot;">​</a></h3><p>流程顺序：</p><ol><li>选择主体或链接范围。</li><li>选择角色。</li><li>设置到期与条件。</li><li>显示影响摘要。</li><li>确认授权。</li><li>分别反馈授权与通知结果。</li></ol><p>高风险范围扩张，例如匿名编辑链接，应有额外确认，但不把所有内部只读邀请都做成阻塞对话框。</p><h3 id="修改与移除" tabindex="-1">修改与移除 <a class="header-anchor" href="#修改与移除" aria-label="Permalink to &quot;修改与移除&quot;">​</a></h3><p>操作名称包含主体和结果，例如：</p><ul><li>“将 Lin 改为只读。”</li><li>“撤销外部审阅链接。”</li><li>“从研究文件夹移除供应商组。”</li></ul><p>若权限继承，操作应指向来源或解释无法在当前资源修改。</p><h2 id="并发与一致性" tabindex="-1">并发与一致性 <a class="header-anchor" href="#并发与一致性" aria-label="Permalink to &quot;并发与一致性&quot;">​</a></h2><h3 id="版本控制" tabindex="-1">版本控制 <a class="header-anchor" href="#版本控制" aria-label="Permalink to &quot;版本控制&quot;">​</a></h3><p>分享面板打开后，另一管理员可能修改 ACL。提交时携带 ACL 版本或 grant 版本；冲突后刷新并保留用户意图，不能静默覆盖对方新增权限。</p><h3 id="缓存" tabindex="-1">缓存 <a class="header-anchor" href="#缓存" aria-label="Permalink to &quot;缓存&quot;">​</a></h3><p>授权缓存必须有精确失效机制。撤销后只更新主数据库但边缘缓存继续放行，是安全失败。关键读取和写入都应验证当前授权版本。</p><h3 id="派生系统" tabindex="-1">派生系统 <a class="header-anchor" href="#派生系统" aria-label="Permalink to &quot;派生系统&quot;">​</a></h3><p>权限传播到：</p><ul><li>搜索索引。</li><li>缩略图与预览。</li><li>评论和 mention。</li><li>通知深链。</li><li>导出、打印和下载。</li><li>API token 与集成。</li><li>离线缓存。</li></ul><p>撤销测试必须覆盖这些入口。</p><h2 id="案例一-临床研究文件夹邀请外部统计师" tabindex="-1">案例一：临床研究文件夹邀请外部统计师 <a class="header-anchor" href="#案例一-临床研究文件夹邀请外部统计师" aria-label="Permalink to &quot;案例一：临床研究文件夹邀请外部统计师&quot;">​</a></h2><h3 id="输入" tabindex="-1">输入 <a class="header-anchor" href="#输入" aria-label="Permalink to &quot;输入&quot;">​</a></h3><p>研究文件夹包含去标识化数据、研究方案和内部伦理记录。外部统计师只需对去标识化数据发表评论，访问 14 天；不得查看内部伦理记录，也不能再次分享。</p><h3 id="结构决策" tabindex="-1">结构决策 <a class="header-anchor" href="#结构决策" aria-label="Permalink to &quot;结构决策&quot;">​</a></h3><p>不能直接分享整个研究根文件夹。建立“外部分析”子文件夹，并明确停止继承内部团队的宽泛编辑角色；仅复制必要的内部管理者授权。</p><p>为外部统计师创建指定用户邀请：</p><ul><li>角色：commenter。</li><li>资源：外部分析子文件夹。</li><li>到期：服务端时间 14 天。</li><li>二次条件：完成组织身份验证。</li><li><code>reshare=false</code>。</li><li>下载能力由数据治理策略决定，不用评论角色名称隐含。</li></ul><h3 id="邀请与激活" tabindex="-1">邀请与激活 <a class="header-anchor" href="#邀请与激活" aria-label="Permalink to &quot;邀请与激活&quot;">​</a></h3><p>授权初始为 pending。通知只包含研究代号，不包含敏感标题。收件人登录验证指定身份后 grant 激活。若邮件失败，界面显示邀请未送达，但授权仍是 pending；管理员可重新发送，不创建重复 grant。</p><h3 id="到期与撤销" tabindex="-1">到期与撤销 <a class="header-anchor" href="#到期与撤销" aria-label="Permalink to &quot;到期与撤销&quot;">​</a></h3><p>到期检查发生在每次请求。打开的浏览器会话在下一次读取评论或文件时被拒绝。搜索、预览和短期下载 URL 同时失效。</p><p>研究提前结束时，管理员撤销 grant。已经下载的文件不会被界面承诺召回，因此数据分类阶段必须先决定是否允许下载。</p><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ul><li>外部统计师只能看到子文件夹及允许内容。</li><li>同邮箱的未受管账户不能接受邀请。</li><li>评论、mention 候选、搜索和通知遵守相同范围。</li><li>14 天边界使用服务端时区准确失效。</li><li>撤销后已有页面、预览 URL 和 API 请求全部拒绝。</li><li>内部伦理文件不会因父级或搜索索引泄露。</li></ul><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>如果只在子文件夹 UI 中隐藏伦理文件，但父级 ACL 仍授予读取，深链和搜索可能继续访问。资源边界必须在授权数据上隔离，不能由文件树显示规则承担。</p><h2 id="案例二-董事会报表的短期查看链接" tabindex="-1">案例二：董事会报表的短期查看链接 <a class="header-anchor" href="#案例二-董事会报表的短期查看链接" aria-label="Permalink to &quot;案例二：董事会报表的短期查看链接&quot;">​</a></h2><h3 id="输入-1" tabindex="-1">输入 <a class="header-anchor" href="#输入-1" aria-label="Permalink to &quot;输入&quot;">​</a></h3><p>季度报表需要发给不使用公司账号的董事。内容允许查看 48 小时，不允许匿名编辑。组织接受持有链接即可查看的风险，但要求每位董事使用独立链接以便单独撤销。</p><h3 id="链接设计" tabindex="-1">链接设计 <a class="header-anchor" href="#链接设计" aria-label="Permalink to &quot;链接设计&quot;">​</a></h3><p>为每位收件人创建独立 capability grant：</p><ul><li>高熵 token。</li><li><code>role=view</code>.</li><li><code>expires_at</code> 精确到时区。</li><li>可选密码通过另一个渠道发送。</li><li>每条 grant 单独记录创建人、收件标签和访问事件。</li></ul><p>页面不加载第三方分析脚本，不把 token 发到日志或外链 Referrer。打开后地址可在安全设计下换为规范 URL 与受控会话，但服务器不能依赖不可靠的 Referrer 传递权限。</p><h3 id="复制界面" tabindex="-1">复制界面 <a class="header-anchor" href="#复制界面" aria-label="Permalink to &quot;复制界面&quot;">​</a></h3><p>每一行显示“董事 A — 仅查看 — 7 月 20 日 18:00 到期”。复制成功才反馈。管理员可复制、轮换或撤销某一行，不影响其他链接。</p><h3 id="验证-1" tabindex="-1">验证 <a class="header-anchor" href="#验证-1" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ul><li>token 不能由相邻值枚举。</li><li>两个链接有不同 grant 与审计。</li><li>到期、撤销和资源删除后无法从 CDN 读取。</li><li>链接不出现在分析、错误跟踪和页面 Referrer。</li><li><code>GET</code> 链接不会执行任何写操作。</li><li>320 CSS px 与键盘下到期和角色文本仍完整。</li></ul><h3 id="失败分支-1" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支-1" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>若所有董事共用一个链接，发现泄露时只能全部撤销，也无法判断哪条分发链需要处理。独立链接提高撤销粒度，但不把访问 IP 当成可靠身份。</p><h2 id="案例三-项目文件移动导致继承变化" tabindex="-1">案例三：项目文件移动导致继承变化 <a class="header-anchor" href="#案例三-项目文件移动导致继承变化" aria-label="Permalink to &quot;案例三：项目文件移动导致继承变化&quot;">​</a></h2><h3 id="输入-2" tabindex="-1">输入 <a class="header-anchor" href="#输入-2" aria-label="Permalink to &quot;输入&quot;">​</a></h3><p>设计文件在“产品团队”文件夹中，继承 40 名员工的查看权限，并直接授予外部代理商编辑权限。文件要移动到“发布材料”文件夹，该父级对全组织可读。</p><h3 id="影响预览" tabindex="-1">影响预览 <a class="header-anchor" href="#影响预览" aria-label="Permalink to &quot;影响预览&quot;">​</a></h3><p>移动确认显示：</p><ul><li>将新增全组织查看权限。</li><li>产品团队的继承来源将消失，但其成员仍因组织权限可查看。</li><li>外部代理商直接编辑权限将保留。</li><li>活跃的指定用户分享链接不变。</li></ul><p>如果文件含尚未发布信息，策略阻止移动，或要求先调整目标文件夹权限。不能先移动再靠用户发现暴露。</p><h3 id="一致性" tabindex="-1">一致性 <a class="header-anchor" href="#一致性" aria-label="Permalink to &quot;一致性&quot;">​</a></h3><p>移动与权限版本变更在同一受控事务或可恢复工作流中完成。搜索索引在收到新 ACL 版本前不向新增主体展示摘要；旧权限缓存失效。</p><h3 id="验证-2" tabindex="-1">验证 <a class="header-anchor" href="#验证-2" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ul><li>移动前后计算有效主体与动作差异。</li><li>并发管理员在确认期间修改目标文件夹 ACL 时触发重新评估。</li><li>外部直接权限是否保留符合明确策略。</li><li>撤销移动后权限来源恢复。</li><li>通知不会向新获得组织访问的所有人广播。</li></ul><h3 id="失败分支-2" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支-2" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>如果预览只说“移动成功”，操作者不知道它同时扩大到全组织。改变父级就是潜在授权变更，确认必须展示新增和失去的有效范围。</p><h2 id="无障碍与交互" tabindex="-1">无障碍与交互 <a class="header-anchor" href="#无障碍与交互" aria-label="Permalink to &quot;无障碍与交互&quot;">​</a></h2><ul><li>分享触发按钮说明资源，例如“共享季度报表”。</li><li>对话框打开后焦点进入标题或首个合理字段，关闭后返回触发按钮。</li><li>主体候选使用可访问 combobox，键盘可搜索、选择和取消。</li><li>当前访问列表中，姓名、权限来源、角色和到期组成可理解单元。</li><li>角色不能只靠颜色或图标表达。</li><li>复制结果使用非打断状态消息。</li><li>撤销确认说明目标链接或主体及影响。</li><li>异步保存期间不让焦点元素消失，冲突后保留选择。</li><li>200% 文本缩放与窄屏下不截断主体、角色和到期信息。</li></ul><h2 id="观测与审计" tabindex="-1">观测与审计 <a class="header-anchor" href="#观测与审计" aria-label="Permalink to &quot;观测与审计&quot;">​</a></h2><h3 id="观测信号" tabindex="-1">观测信号 <a class="header-anchor" href="#观测信号" aria-label="Permalink to &quot;观测信号&quot;">​</a></h3><ul><li>按 scope 和 role 统计新 grant，不记录秘密 token。</li><li>外部邀请接受、过期和撤销。</li><li>匿名链接创建、轮换与异常访问。</li><li>到期后被拒绝的访问和缓存放行告警。</li><li>ACL 冲突、通知失败和目录误选。</li><li>权限变更后搜索与预览传播延迟。</li><li>资源移动导致的有效主体变化。</li></ul><p>“分享次数”不是协作价值，也不能替代高风险范围审核。</p><h3 id="审计事件" tabindex="-1">审计事件 <a class="header-anchor" href="#审计事件" aria-label="Permalink to &quot;审计事件&quot;">​</a></h3><p>记录：</p><ul><li>谁在何时对哪个资源创建或修改哪条 grant。</li><li>旧角色与新角色。</li><li>到期与撤销原因。</li><li>继承来源变化。</li><li>链接 grant ID，不记录完整 token。</li><li>策略拒绝与管理员覆盖。</li></ul><p>审计读取本身需要严格授权和保留限制。</p><h2 id="调试顺序" tabindex="-1">调试顺序 <a class="header-anchor" href="#调试顺序" aria-label="Permalink to &quot;调试顺序&quot;">​</a></h2><ol><li>固定主体、资源、动作和服务端时间。</li><li>列出直接、群组、继承、策略和链接来源。</li><li>计算有效动作集合。</li><li>检查组织外部协作与数据分类策略。</li><li>检查 grant 版本、到期和撤销状态。</li><li>检查缓存、索引、预览、评论和下载入口。</li><li>检查通知是否与授权结果分开。</li><li>复测键盘、状态消息和窄屏。</li></ol><h2 id="失败注入" tabindex="-1">失败注入 <a class="header-anchor" href="#失败注入" aria-label="Permalink to &quot;失败注入&quot;">​</a></h2><ol><li>分享面板打开时另一管理员改变 ACL。</li><li>群组成员在请求期间被移除。</li><li>链接在页面打开后立即撤销。</li><li>到期任务停止运行。</li><li>邮件发送失败但 grant 已创建。</li><li>资源移动到更宽权限父级。</li><li>token 出现在错误上报或 Referrer。</li><li>删除后恢复资源。</li><li>最后一名管理者尝试移除自己。</li></ol><h2 id="综合练习-设计端到端分享系统" tabindex="-1">综合练习：设计端到端分享系统 <a class="header-anchor" href="#综合练习-设计端到端分享系统" aria-label="Permalink to &quot;综合练习：设计端到端分享系统&quot;">​</a></h2><p>为支持文件夹继承、外部用户与匿名链接的资源库交付：</p><ol><li>grant、role、principal 和 condition 数据模型。</li><li>直接、群组、继承、策略和链接的有效权限算法。</li><li>邀请 pending、active、expired、revoked 状态机。</li><li>角色—动作表与高风险确认。</li><li>capability URL 的生成、存储、复制、过期、轮换和撤销。</li><li>资源移动与停止继承的影响预览。</li><li>缓存、索引、通知、附件和 API 的撤权测试。</li></ol><p>验收标准：</p><ul><li>分享面板能解释所有有效访问来源。</li><li>每个角色展开为明确动作集合。</li><li>通知失败不会被误写成授权失败或成功。</li><li>匿名链接可独立撤销且 token 不进入日志。</li><li>到期由每次服务端授权判断执行。</li><li>资源移动前展示权限扩大与缩小。</li><li>已下载副本不会被承诺可远程召回。</li></ul><h2 id="来源-1" tabindex="-1">来源 <a class="header-anchor" href="#来源-1" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.nist.gov/publications/guide-attribute-based-access-control-abac-definition-and-considerations-0" target="_blank" rel="noreferrer">NIST：Guide to Attribute Based Access Control</a>（访问日期：2026-07-18）</li><li><a href="https://www.w3.org/TR/capability-urls/" target="_blank" rel="noreferrer">W3C TAG：Good Practices for Capability URLs</a>（访问日期：2026-07-18）</li><li><a href="https://developers.google.com/workspace/drive/api/guides/manage-sharing" target="_blank" rel="noreferrer">Google Drive API：Share Files, Folders, and Drives</a>（访问日期：2026-07-18）</li><li><a href="https://developers.google.com/workspace/drive/api/reference/rest/v3/permissions" target="_blank" rel="noreferrer">Google Drive API：Permissions Resource</a>（访问日期：2026-07-18）</li><li><a href="https://learn.microsoft.com/en-us/graph/api/driveitem-createlink?view=graph-rest-1.0" target="_blank" rel="noreferrer">Microsoft Graph：Create a Sharing Link</a>（访问日期：2026-07-18）</li></ul>`,169)])])}const b=t(r,[["render",d]]);export{u as __pageData,b as default};
